from unittest.mock import patch
from trio_data_providers.tradingview_provider import (
    _analyst_sent_from_rec_mark, _detect_market, _normalize_tickers,
)


def test_tv_market_detection():
    assert _detect_market(["NASDAQ:AAPL"]) == "america"
    assert _detect_market(["MYX:1155"]) == "malaysia"
    assert _detect_market(["AAPL"]) == "america"  # default


def test_tv_ticker_normalization():
    assert _normalize_tickers(["AAPL", "msft"], "america") == ["NASDAQ:AAPL", "NASDAQ:MSFT"]
    assert _normalize_tickers(["1155"], "malaysia") == ["MYX:1155"]


def test_tv_analyst_sent_mapping():
    assert _analyst_sent_from_rec_mark(1.0) == 5.0    # strong buy
    assert _analyst_sent_from_rec_mark(-1.0) == 1.0   # strong sell
    assert _analyst_sent_from_rec_mark(0.0) == 3.0    # neutral
    assert _analyst_sent_from_rec_mark(None) is None


def test_tv_fetch_with_mocked_scanner():
    fake = MagicMock()
    fake.raise_for_status.return_value = None
    fake.json.return_value = {
        "data": [{
            "s": "NASDAQ:AAPL",
            "d": [
                "AAPL", "Apple Inc.", 170.0,        # name, description, close
                100_000_000.0,                       # average_volume_90d_calc
                200.0,                               # price_target_average
                0.55,                                # dividend_yield_recent
                3.4,                                 # ALT.Z
                0.6,                                 # recommendation_mark
                15_700_000_000.0,                    # total_shares_outstanding
            ],
        }],
    }
    with patch("requests.post", return_value=fake):
        p = get_provider("tradingview")
