"use client";

import { useState } from "react";
import {
  fetchUniverse,
  score,
  type ModelId,
  type ProviderId,
  type ScoreResponse,
} from "@/lib/api";

interface Props {
  onResult: (resp: ScoreResponse, modelId: ModelId) => void;
}

const PROVIDERS: { id: ProviderId; label: string; hint: string }[] = [
  { id: "yfinance",    label: "yfinance — US (S&P 500)",         hint: "AAPL, MSFT, NVDA" },
  { id: "tradingview", label: "TradingView — US or KLSE",         hint: "NASDAQ:AAPL or MYX:1155" },
  { id: "i3investor",  label: "i3investor — KLSE (partial)",      hint: "1155, 5285, 1023" },
  { id: "bloomberg",   label: "Bloomberg — credentials required", hint: "(stub)" },
];

export function LiveUniverseCard({ onResult }: Props) {
  const [provider, setProvider] = useState<ProviderId>("yfinance");
  const [model, setModel] = useState<ModelId>("bos");
  const [tickers, setTickers] = useState("AAPL, MSFT, NVDA, GOOG, META, AMZN, TSLA, BRK-B");
  const [busy, setBusy] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [info, setInfo] = useState<string | null>(null);

  async function run() {
    setBusy(true);
    setError(null);
    setInfo(null);
    try {
      const list = tickers.split(/[,\s]+/).map((s) => s.trim()).filter(Boolean);
      if (list.length === 0) throw new Error("Enter at least one ticker.");
      const u = await fetchUniverse(provider, list, model);
      setInfo(`Fetched ${u.rows.length} rows from ${u.provider}. ${u.warnings.join(" · ")}`);
      const resp = await score(model, u.universe, u.rows);
      onResult(resp, model);
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setBusy(false);
    }
  }

  const hint = PROVIDERS.find((p) => p.id === provider)?.hint;

  return (
    <section className="rounded-lg border border-slate-200 bg-white p-6">
      <h2 className="text-base font-semibold text-ink">Or fetch a live universe</h2>
      <p className="mt-1 text-xs text-slate-500">
        Paid providers (Bloomberg) need env vars. yfinance and TradingView work out of the box;
        i3investor is partial KLSE coverage.
      </p>

      <div className="mt-4 grid gap-3">
        <label className="text-sm">
          <span className="block font-medium text-slate-700">Provider</span>
          <select
            value={provider}
            onChange={(e) => setProvider(e.target.value as ProviderId)}
            className="mt-1 w-full rounded-md border border-slate-300 px-3 py-2 text-sm"
          >
            {PROVIDERS.map((p) => (
              <option key={p.id} value={p.id}>{p.label}</option>
            ))}
          </select>
        </label>

        <label className="text-sm">
          <span className="block font-medium text-slate-700">Model</span>
          <select
            value={model}
            onChange={(e) => setModel(e.target.value as ModelId)}
            className="mt-1 w-full rounded-md border border-slate-300 px-3 py-2 text-sm"
          >
            <option value="bos">BOS — 5-Factor</option>
            <option value="mos">MOS — Margin-of-Safety</option>
            <option value="four_factor">4-Factor — Legacy</option>
          </select>
        </label>

        <label className="text-sm">
          <span className="block font-medium text-slate-700">
            Tickers <span className="font-normal text-slate-400">e.g. {hint}</span>
          </span>
          <textarea
            value={tickers}
            onChange={(e) => setTickers(e.target.value)}
            rows={3}
            className="mt-1 w-full rounded-md border border-slate-300 px-3 py-2 font-mono text-xs"
          />
        </label>

        <button
          onClick={run}
          disabled={busy}
          className="rounded-md bg-trust px-4 py-2 text-sm font-medium text-white hover:bg-blue-700 disabled:opacity-50"
        >
          {busy ? "Fetching & scoring…" : "Fetch & score"}
        </button>
      </div>

      {info && (
        <div className="mt-4 rounded-md border border-blue-200 bg-blue-50 px-3 py-2 text-xs text-blue-900">
          {info}
        </div>
      )}
      {error && (
        <div className="mt-4 rounded-md border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-800">
          {error}
        </div>
      )}
    </section>
  );
}
