        raise HTTPException(status_code=502, detail=str(e)) from e

    return {
        "provider": result.provider,
        "universe": result.universe,
        "rows": result.rows,
        "warnings": result.warnings,
        "coverage": sorted(provider.coverage(model)),
    }

