export type Recommendation =
  | "BUY-BUY"
  | "BUY"
  | "SELL"
  | "SELL-SELL"
  | "UNRANKED";

export type Band = "BUY" | "NEUTRAL" | "SELL" | "N/A";

export interface FactorBreakdown {
  id: string;
  label: string;
  raw: number | null;
  band: Band;
  sub_score: number;
  weight: number;
  contribution: number;
  flags: string[];
}

export interface StockResult {
  ticker: string;
  name: string | null;
  final_score: number | null;
  quartile: number | null;
  recommendation: Recommendation;
  factors: FactorBreakdown[];
  explanation: string | null;
  flags: string[];
}

export interface ScoreResponse {
  model_version: string;
  as_of: string;
  universe: string;
  n_rows: number;
  n_scored: number;
  results: StockResult[];
  warnings: string[];
}

export type ModelId = "bos" | "mos" | "four_factor";

export type ProviderId = "yfinance" | "tradingview" | "i3investor" | "bloomberg";

export interface UniverseResponse {
  provider: string;
  universe: string;
  rows: Record<string, unknown>[];
  warnings: string[];
  coverage: string[];
}

export async function fetchUniverse(
  provider: ProviderId,
  tickers: string[],
  model: ModelId
): Promise<UniverseResponse> {
  const res = await fetch(`/api/universe/${provider}?model=${model}`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ tickers }),
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Provider ${provider} ${res.status}: ${text}`);
  }
  return res.json();
}

export async function score(
  model: ModelId,
  universe: string,
  rows: Record<string, unknown>[],
  opts: { legacy?: boolean } = {}
): Promise<ScoreResponse> {
  const qs = new URLSearchParams({ model });
  if (opts.legacy) qs.set("legacy", "true");

  const res = await fetch(`/api/score?${qs.toString()}`, {
    method: "POST",
    headers: { "content-type": "application/json" },
    body: JSON.stringify({ universe, rows }),
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(`API ${res.status}: ${text}`);
  }
  return res.json();
}

