      const uni = await fetchUniverse(provider, list, model);
      setWarnings(uni.warnings);
      const resp = await score(model, uni.universe, uni.rows);
      onResult(resp, model);
    } catch (e) {
      setError(e instanceof Error ? e.message : String(e));
